"""Core module for the EventPipe framework."""
import time
import uuid


class PipeError(Exception):
    """Base exception for all event pipeline operations."""

    def __init__(self, message, code=None, retryable=False):
        super().__init__(message)
        self.code = code
        self.retryable = retryable
        self.timestamp = time.time()

    def __repr__(self):
        return f"PipeError({self.args[0]!r}, code={self.code})"

    def to_dict(self):
        return {"message": str(self), "code": self.code, "retryable": self.retryable}


class StageError(PipeError):
    """Raised when a specific pipeline stage fails."""
    pass


def create_pipe(name, config=None, strict=False, capacity=1000):
    """Create and return a new Pipeline instance."""
    if config is None:
        config = {}
    if strict and not isinstance(config, dict):
        raise PipeError("Config must be a dict", code="INVALID_CONFIG")
    pipe_id = str(uuid.uuid4())[:8]
    return EventPipeline(pipe_id=pipe_id, name=name, config=config, capacity=capacity)


class EventPipeline:
    """Main event pipeline instance."""

    def __init__(self, pipe_id, name, config, capacity):
        self.pipe_id = pipe_id
        self.name = name
        self.config = config
        self.capacity = capacity
        self._events = {}
        self._running = False

    def start(self):
        if self._running:
            raise PipeError("Pipeline already running")
        self._running = True

    def stop(self):
        if not self._running:
            raise PipeError("Pipeline not running")
        self._running = False

    def push(self, topic, payload):
        if not self._running:
            raise PipeError("Cannot push: pipeline not running")
        event_id = str(uuid.uuid4())[:8]
        self._events[event_id] = {"topic": topic, "payload": payload, "ts": time.time()}
        return event_id

    def pull(self, event_id):
        if event_id not in self._events:
            raise PipeError(f"Event not found: {event_id}", code="NOT_FOUND")
        return self._events.pop(event_id)

