"""Event source connectors for the pipeline."""
from eventpipe.core import PipeError, create_pipe


class EventSource:
    """Produces events from an upstream data source."""

    def __init__(self, name, format="json"):
        self.name = name
        self.format = format
        self._pipeline = create_pipe(f"source-{name}", {"role": "source"})

    def connect(self):
        self._pipeline.start()

    def emit(self, topic, payload):
        if not self._pipeline._running:
            raise PipeError(f"Source '{self.name}' not connected")
        return self._pipeline.push(topic, payload)

    def disconnect(self):
        self._pipeline.stop()

