from eventpipe.core import PipeError, create_pipe


class EventSink:
    """Consumes events and writes them to a destination."""

    def __init__(self, name, format="json"):
        self.name = name
        self.format = format
        self._pipeline = create_pipe(f"sink-{name}", {"role": "sink"})

    def connect(self):
        self._pipeline.start()

    def receive(self, event_id):
        return self._pipeline.pull(event_id)

    def disconnect(self):
        self._pipeline.stop()

