"""Event filtering operations."""
from eventpipe.core import PipeError


class EventFilter:
    """Filters events based on predicates."""

    def __init__(self, name="default"):
        self.name = name
        self._predicates = []

    def add_predicate(self, func, label="unnamed"):
        """Add a filter predicate."""
        self._predicates.append({"func": func, "label": label})

    def apply(self, events):
        """Apply all predicates, returning matching events."""
        result = []
        for ev in events:
            try:
                if all(p["func"](ev) for p in self._predicates):
                    result.append(ev)
            except Exception as e:
                raise PipeError(f"Filter '{self.name}' failed: {e}")
        return result

    def match_one(self, event):
        """Check if a single event passes all predicates."""
        try:
            return all(p["func"](event) for p in self._predicates)
        except Exception as e:
            raise PipeError(f"Filter match failed: {e}")

seed_files.eventpipe/mapper.py:
"""Event mapping (transformation) operations."""
from eventpipe.core import PipeError


class EventMapper:
    """Transforms events by applying mapping functions."""

    def __init__(self, name="default"):
        self.name = name
        self._transforms = []

    def add(self, func, label="unnamed"):
        """Register a transformation function."""
        self._transforms.append({"func": func, "label": label})

    def apply(self, event):
        """Apply all transforms to a single event."""
        result = event
        for t in self._transforms:
            try:
                result = t["func"](result)
            except Exception as e:
                raise PipeError(f"Mapper '{t['label']}' failed: {e}")
        return result

    def apply_batch(self, events):
        """Apply all transforms to a batch of events."""
        results = []
        for ev in events:
            try:
                results.append(self.apply(ev))
            except PipeError:
                raise
        return results

