"""Event splitter for fan-out patterns."""
from eventpipe.core import PipeError, create_pipe


class EventSplitter:
    """Splits a single event stream into multiple output streams."""

    def __init__(self, name, num_outputs=2):
        self.name = name
        self._outputs = {}
        for i in range(num_outputs):
            self._outputs[i] = create_pipe(f"split-{name}-{i}", {"partition": i})

    def split(self, event, key_func=None):
        """Route an event to an output based on the key function."""
        if key_func is None:
            key_func = lambda e: 0
        idx = key_func(event) % len(self._outputs)
        if idx not in self._outputs:
            raise PipeError(f"Output index {idx} not found in splitter '{self.name}'")
        return self._outputs[idx]

    def output_count(self):
        return len(self._outputs)

seed_files.eventpipe/merger.py:
"""Event merger for fan-in patterns."""
from eventpipe.core import PipeError, create_pipe


class EventMerger:
    """Merges multiple event streams into a single output."""

    def __init__(self, name, strategy="concat"):
        self.name = name
        self.strategy = strategy
        self._output = create_pipe(f"merge-{name}", {"strategy": strategy})

    def merge(self, *streams):
        """Merge multiple event lists into one."""
        if not streams:
            raise PipeError(f"Merger '{self.name}': at least one stream required")
        result = []
        for s in streams:
            result.extend(s)
        return result

    def stream_count(self, *streams):
        return sum(len(s) for s in streams)

