"""Event routing for topic-based delivery."""
from eventpipe.core import PipeError, create_pipe


class EventRoute:
    """A single topic route."""

    def __init__(self, pattern, handler):
        self.pattern = pattern
        self.handler = handler

    def matches(self, topic):
        return topic.startswith(self.pattern)

    def dispatch(self, event):
        try:
            return self.handler(event)
        except Exception as e:
            raise PipeError(f"Route '{self.pattern}' dispatch failed: {e}")


class EventRouter:
    """Routes events to handlers by topic."""

    def __init__(self):
        self._routes = []
        self._dead_letter = create_pipe("dead-letter", {"max_size": 500})

    def add_route(self, pattern, handler):
        self._routes.append(EventRoute(pattern, handler))

    def route(self, topic, event):
        for r in self._routes:
            if r.matches(topic):
                return r.dispatch(event)
        raise PipeError(f"No route for topic '{topic}'", code="NO_ROUTE")

