"""Event buffering for backpressure handling."""
from eventpipe.core import PipeError, create_pipe


class EventBuffer:
    """Buffers events to handle backpressure."""

    def __init__(self, name, max_size=100):
        self.name = name
        self.max_size = max_size
        self._store = create_pipe(f"buffer-{name}", {"max": max_size})
        self._items = []

    def add(self, event):
        if len(self._items) >= self.max_size:
            raise PipeError(f"Buffer '{self.name}' is full ({self.max_size})")
        self._items.append(event)

    def flush(self):
        items = list(self._items)
        self._items.clear()
        return items

    def size(self):
        return len(self._items)

