"""Pipeline monitoring and health checks."""
from eventpipe.core import PipeError


class PipelineMonitor:
    """Monitors pipeline health and collects error metrics."""

    def __init__(self):
        self._metrics = {}
        self._errors = []

    def record_metric(self, name, value):
        """Record a named metric value."""
        if name not in self._metrics:
            self._metrics[name] = []
        self._metrics[name].append(value)

    def record_error(self, exc):
        """Record an error occurrence, with extra detail for PipeError."""
        entry = {"type": type(exc).__name__, "message": str(exc)}
        if isinstance(exc, PipeError):
            entry["code"] = exc.code
            entry["retryable"] = exc.retryable
        self._errors.append(entry)

    def get_metric(self, name):
        return self._metrics.get(name, [])

    def error_count(self):
        return len(self._errors)

