"""Pipeline event logging."""
from eventpipe.core import PipeError


class PipelineLogger:
    """Logs events and errors in the pipeline."""

    def __init__(self, name="default"):
        self.name = name
        self._entries = []

    def log_event(self, event, level="info"):
        """Log a pipeline event."""
        self._entries.append({"level": level, "event": event})

    def log_error(self, exc):
        """Log an exception, with extra detail for PipeError."""
        entry = {"level": "error", "type": type(exc).__name__, "message": str(exc)}
        if isinstance(exc, PipeError):
            entry["code"] = exc.code
        self._entries.append(entry)

    def get_entries(self, level=None):
        if level:
            return [e for e in self._entries if e["level"] == level]
        return list(self._entries)

    def error_entries(self):
        return self.get_entries(level="error")

