"""Pipeline configuration management."""
import json
from eventpipe.core import PipeError, create_pipe


class PipelineConfig:
    """Manages pipeline configuration and creates pipelines from config."""

    def __init__(self):
        self._configs = {}

    def register(self, name, config_dict):
        """Register a named pipeline configuration."""
        self._configs[name] = config_dict

    def get(self, name):
        """Retrieve a configuration by name."""
        if name not in self._configs:
            raise PipeError(f"Unknown config: {name}", code="NOT_FOUND")
        return self._configs[name]

    def build_pipeline(self, name):
        """Build a pipeline from a registered config."""
        cfg = self.get(name)
        return create_pipe(name, config=cfg, strict=True)

    def load_json(self, raw):
        """Load configuration from a JSON string."""
        try:
            data = json.loads(raw)
            for name, cfg in data.items():
                self.register(name, cfg)
        except json.JSONDecodeError as e:
            raise PipeError(f"Invalid config JSON: {e}")

