"""Event validation module."""
import json
from eventpipe.core import PipeError, create_pipe


class EventValidator:
    """Validates events against rules before they enter the pipeline."""

    def __init__(self):
        self._rules = {}
        self._store = create_pipe("validator-store", {"type": "validation"})

    def add_rule(self, field, rule_func, message="Validation failed"):
        """Add a validation rule for a field."""
        self._rules[field] = {"func": rule_func, "message": message}

    def check(self, event):
        """Validate an event against all rules."""
        errors = []
        for field_name, rule in self._rules.items():
            value = event.get(field_name)
            if not rule["func"](value):
                errors.append(f"{field_name}: {rule['message']}")
        if errors:
            raise PipeError("; ".join(errors), code="VALIDATION")
        return True

    def validate_json(self, raw):
        """Validate a JSON string as an event."""
        try:
            event = json.loads(raw)
        except json.JSONDecodeError as e:
            raise PipeError(f"Invalid event JSON: {e}")
        return self.check(event)
